1419→    /// Multi-branch scenario: f(x) has branches at x>10, x==42, x<100.
1420→    /// Starting from x=0 (all branches false), Z3 can find inputs for each path.
1421→    #[test]
1422→    fn multi_branch_z3_exploration() {
1423→        // Simulate path from x=0: branches x>10 (false), x==42 (false), x<100 (true).
1424→        // Path constraints as recorded: NOT(x>10), NOT(x==42), x<100.
1425→        let not_x_gt_10 = SymExpr::UnOp {
1426→            op: crate::sym_expr::UnOpKind::Not,
1427→            operand: Box::new(SymExpr::BinOp {
1428→                op: BinOpKind::Gt,
1429→                left: Box::new(SymExpr::Param {
1430→                    name: "x".into(),
1431→                    path: vec![],
1432→                }),
1433→                right: Box::new(SymExpr::Const(ConstValue::Int(10))),
1434→            }),
1435→        };
1436→        let not_x_eq_42 = SymExpr::UnOp {
1437→            op: crate::sym_expr::UnOpKind::Not,
1438→            operand: Box::new(SymExpr::BinOp {
1439→                op: BinOpKind::Eq,
1440→                left: Box::new(SymExpr::Param {
1441→                    name: "x".into(),
1442→                    path: vec![],
1443→                }),
1444→                right: Box::new(SymExpr::Const(ConstValue::Int(42))),
1445→            }),
1446→        };
1447→        let x_lt_100 = SymExpr::BinOp {
1448→            op: BinOpKind::Lt,
1449→            left: Box::new(SymExpr::Param {
1450→                name: "x".into(),
1451→                path: vec![],
1452→            }),
1453→            right: Box::new(SymExpr::Const(ConstValue::Int(100))),
1454→        };
1455→
1456→        let constraints = [not_x_gt_10, not_x_eq_42, x_lt_100];
1457→
1458→        // Negate constraint[0]: flip NOT(x>10) → x>10. With prefix empty, just x>10.
1459→        let result =
1460→            solver::solve_for_new_path(&constraints, 0, None, &[]).expect("should solve for branch 0");
1461→        match result {
1462→            SolveResult::Sat(values) => {
1463→                let x = match values.get("x") {
1464→                    Some(ConcreteValue::Int(v)) => *v,
1465→                    other => panic!("expected Int for x, got {other:?}"),
1466→                };
1467→                assert!(x > 10, "flipping branch 0 should give x>10, got {x}");
1468→            }
1469→            SolveResult::Unsat => panic!("expected sat for branch 0"),
1470→        }
