1956→/// Generate return values for a single mock, dispatching to error-aware or
1957→/// category-shaped generators as needed.
1958→fn generate_mock_return_values(
1959→    return_type: &TypeInfo,
1960→    category: IoCategory,
1961→    count: usize,
1962→    rng: &mut impl Rng,
1963→    caps: Option<&FrontendCapabilities>,
1964→) -> (Vec<Value>, MockBehavior) {
1965→    // Result complex type: alternates ok/err variants using the tagged wire format.
1966→    if matches!(return_type, TypeInfo::Complex { kind: ComplexKind::Result, .. }) {
1967→        let values = (0..count)
1968→            .map(|i| {
1969→                if i % 2 == 0 {
1970→                    let inner = generate_random_value(&TypeInfo::Unknown, rng, caps);
1971→                    json!({"__complex_type": "result", "ok": true, "value": inner})
1972→                } else {
1973→                    json!({"__complex_type": "result", "ok": false, "value": "mock error"})
1974→                }
1975→            })
1976→            .collect();
1977→        return (values, MockBehavior::ReturnGenerated);
1978→    }
1979→
1980→    // Union-with-Error: alternate success and error variants.
1981→    // Error variants use generate_error() directly for the tagged format.
1982→    if let TypeInfo::Union { variants } = return_type {
1983→        let (error_indices, success_indices) = partition_error_variants(variants);
1984→        if !error_indices.is_empty() && !success_indices.is_empty() {
1985→            let mut values = Vec::with_capacity(count);
1986→            for i in 0..count {
1987→                if i % 2 == 0 {
1988→                    let idx = success_indices[rng.random_range(0..success_indices.len())];
1989→                    values.push(generate_random_value(&variants[idx], rng, caps));
1990→                } else {
1991→                    let idx = error_indices[rng.random_range(0..error_indices.len())];
